# genai_sdk/features/completions.py
import warnings

class CompletionsAPI:
    def create(self, prompt: str, model: str = "davinci-002", **kwargs):
        warnings.warn(
            "CompletionsAPI.create() is deprecated and will be removed on 2026-03-01. "
            "Use ChatAPI.complete() instead. Migration guide: "
            "https://docs.example.com/migration/completions-to-chat",
            DeprecationWarning,
            stacklevel=2,  # points warning at the caller's line, not this line
        )
        return self._create_impl(prompt, model, **kwargs)

# app/routes/sunset_410.py
# Replaces the deprecated endpoint with a 410 Gone response
# Active from T-0 to T+7, then the route is fully removed

import json
from fastapi import APIRouter, Response

router = APIRouter()

SUNSET_DATE = "2026-03-01"
MIGRATION_GUIDE_URL = "https://docs.example.com/migration/completions-to-chat"

@router.api_route("/v1/completions", methods=["GET", "POST"])
async def completions_gone():
    body = json.dumps({
        "error": {
            "type": "feature_removed",
            "code": "sunset",
            "message": (
                "The /v1/completions endpoint was sunset on " + SUNSET_DATE +
                ". Please migrate to /v1/chat/completions."
            ),
            "migration_guide": MIGRATION_GUIDE_URL,
            "support": "support@example.com",
        }
    }, indent=2)
    return Response(
        content=body,
        status_code=410,
        media_type="application/json",
        headers={
            "Link": '<' + MIGRATION_GUIDE_URL + '>; rel="successor-version"',
        },
    )
